// Generated by OrchestKit Claude Plugin
// Created: 2026-04-22

/**
 * PreCompact Task-Done Prompt — Issue #1469
 *
 * Nudges `/clear` at the natural breakpoint right before CC runs automatic
 * compaction. Fires only when 3 independent signals align to suggest the
 * current task cluster has wrapped up:
 *
 *   1. Git working tree quiet (<= 2 uncommitted changes)
 *   2. No subagent spawns in the last 5 minutes
 *   3. Recent decisions log mentions a wrap-up keyword
 *
 * When >= 2 of 3 signals match, the hook blocks the compact with a short
 * stopReason explaining the choice. The user types /clear for a fresh
 * session or /compact to keep history. A 30-minute cooldown prevents
 * repeated nudges in the same session.
 *
 * Opt-out: ORK_NO_PRECOMPACT_PROMPT=1
 *
 * Telemetry: appends every decision to
 * `${projectDir}/.claude/telemetry/pre-compact-decisions.jsonl` so
 * accept/decline rates can be reviewed.
 *
 * Runs after pre-compact-guard (which has strict safety semantics) and
 * before pre-compact-saver (which snapshots state unconditionally). If this
 * hook blocks, the saver never runs — fine, because no compact happened.
 */

import { existsSync, readFileSync, mkdirSync, appendFileSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import { join, dirname } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getProjectDir } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'pre-compact-task-done-prompt';
const COOLDOWN_MS = 30 * 60 * 1000;
const QUIESCENT_WINDOW_MS = 5 * 60 * 1000;
const MAX_DIRTY_FILES = 2;

const BREAKPOINT_KEYWORDS = [
  'merged',
  'shipped',
  'closed #',
  'closes #',
  'released',
  'pushed',
  'deployed',
  'resolved',
  'pr merge',
  'gh pr merge',
  'main →',
  'squash',
];

interface TelemetryEntry {
  timestamp: string;
  fired: boolean;
  signals: {
    gitQuiet: boolean;
    quiescent: boolean;
    breakpointKeywords: boolean;
  };
  cooldown?: boolean;
  optOut?: boolean;
}

function readLastLines(path: string, n: number): string[] {
  if (!existsSync(path)) return [];
  try {
    const content = readFileSync(path, 'utf8').trim();
    if (!content) return [];
    return content.split('\n').filter(Boolean).slice(-n);
  } catch {
    return [];
  }
}

function countChangedFiles(projectDir: string): number {
  try {
    const output = execFileSync('git', ['diff', '--name-only', 'HEAD'], {
      encoding: 'utf8',
      timeout: 2000,
      cwd: projectDir,
      stdio: ['pipe', 'pipe', 'pipe'],
      windowsHide: true,
    });
    return output.trim().split('\n').filter(Boolean).length;
  } catch {
    return -1;
  }
}

function gitQuiet(projectDir: string): boolean {
  const n = countChangedFiles(projectDir);
  return n >= 0 && n <= MAX_DIRTY_FILES;
}

function isQuiescent(projectDir: string): boolean {
  const path = join(projectDir, '.claude', 'logs', 'subagent-spawns.jsonl');
  // Missing or empty spawn log = no evidence of quiescence. Don't treat
  // "no data" as a positive signal — that would false-positive in sessions
  // where this hook runs before any subagents have been tracked.
  if (!existsSync(path)) return false;
  const lines = readLastLines(path, 10);
  if (lines.length === 0) return false;
  const cutoff = Date.now() - QUIESCENT_WINDOW_MS;
  for (const line of lines) {
    try {
      const entry = JSON.parse(line);
      if (typeof entry.timestamp === 'string') {
        const ts = new Date(entry.timestamp).getTime();
        if (Number.isFinite(ts) && ts > cutoff) return false;
      }
    } catch {
      // ignore unparseable lines
    }
  }
  return true;
}

function hasBreakpointKeyword(projectDir: string): boolean {
  const lines = readLastLines(join(projectDir, '.claude', 'logs', 'decisions.jsonl'), 3);
  if (lines.length === 0) return false;
  const combined = lines.join(' ').toLowerCase();
  return BREAKPOINT_KEYWORDS.some(kw => combined.includes(kw));
}

function lastFireTimestamp(telemetryPath: string): number {
  const lines = readLastLines(telemetryPath, 20);
  for (let i = lines.length - 1; i >= 0; i--) {
    try {
      const entry = JSON.parse(lines[i]) as TelemetryEntry;
      if (entry.fired) {
        const ts = new Date(entry.timestamp).getTime();
        if (Number.isFinite(ts)) return ts;
      }
    } catch {
      // skip
    }
  }
  return 0;
}

function appendTelemetry(path: string, entry: TelemetryEntry): void {
  try {
    mkdirSync(dirname(path), { recursive: true });
    appendFileSync(path, `${JSON.stringify(entry)}\n`);
  } catch {
    // telemetry is best-effort
  }
}

export function preCompactTaskDonePrompt(
  _input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const projectDir = ctx.projectDir || getProjectDir();
  const telemetryPath = join(
    projectDir,
    '.claude',
    'telemetry',
    'pre-compact-decisions.jsonl',
  );

  if (process.env.ORK_NO_PRECOMPACT_PROMPT === '1') {
    appendTelemetry(telemetryPath, {
      timestamp: new Date().toISOString(),
      fired: false,
      signals: { gitQuiet: false, quiescent: false, breakpointKeywords: false },
      optOut: true,
    });
    return outputSilentSuccess();
  }

  const now = Date.now();
  const last = lastFireTimestamp(telemetryPath);
  if (last > 0 && now - last < COOLDOWN_MS) {
    appendTelemetry(telemetryPath, {
      timestamp: new Date(now).toISOString(),
      fired: false,
      signals: { gitQuiet: false, quiescent: false, breakpointKeywords: false },
      cooldown: true,
    });
    ctx.log(HOOK_NAME, `skipped — cooldown (last fire ${Math.round((now - last) / 60000)}m ago)`);
    return outputSilentSuccess();
  }

  const signals = {
    gitQuiet: gitQuiet(projectDir),
    quiescent: isQuiescent(projectDir),
    breakpointKeywords: hasBreakpointKeyword(projectDir),
  };
  const signalCount =
    Number(signals.gitQuiet) +
    Number(signals.quiescent) +
    Number(signals.breakpointKeywords);
  const fire = signalCount >= 2;

  appendTelemetry(telemetryPath, {
    timestamp: new Date(now).toISOString(),
    fired: fire,
    signals,
  });

  if (!fire) {
    ctx.log(
      HOOK_NAME,
      `silent — signals: gitQuiet=${signals.gitQuiet} quiescent=${signals.quiescent} kws=${signals.breakpointKeywords}`,
    );
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, 'blocking compact — task-done breakpoint detected');

  return {
    continue: false,
    decision: 'block',
    stopReason:
      'Compact paused — task looks wrapped up. Type /clear for a fresh session (zero context cost) or /compact to keep history and continue.',
  };
}

export default preCompactTaskDonePrompt;
